
'use server';

/**
 * @fileOverview An AI flow that generates a video from a single combined image using Pollo.ai.
 *
 * - generateKissVideo - A function that handles the video generation process.
 * - GenerateKissVideoInput - The input type for the generateKissVideo function.
 * - GenerateKissVideoOutput - The return type for the generateKissVideo function.
 */
import type { RequestInit, Response } from 'node-fetch';
import {z} from 'genkit';

// We need to dynamically import node-fetch as it's a CommonJS module.
const fetch = (url: string, init?: RequestInit): Promise<Response> =>
  import('node-fetch').then(({ default: fetch }) => fetch(url, init));


// The flow now only expects one image URI (the combined one).
const GenerateKissVideoInputSchema = z.object({
  image1DataUri: z
    .string()
    .describe(
      "A photo of the two people side-by-side, as a data URI that must include a MIME type and use Base64 encoding. Expected format: 'data:<mimetype>;base64,<encoded_data>'."
    ),
  image2DataUri: z.string().optional() // Keep this optional for schema compatibility but it won't be used
});

export type GenerateKissVideoInput = z.infer<typeof GenerateKissVideoInputSchema>;

const GenerateKissVideoOutputSchema = z.object({
  videoDataUri: z.string().optional().describe('The generated video as a data URI.'),
  error: z.string().optional().describe('An error message if the generation failed.'),
});

export type GenerateKissVideoOutput = z.infer<typeof GenerateKissVideoOutputSchema>;

export async function generateKissVideo(input: GenerateKissVideoInput): Promise<GenerateKissVideoOutput> {
  console.log('[FLOW_LOG] Starting generateKissVideo flow.');
  try {
    // This is now a direct passthrough to the single-image generation flow.
    const result = await videoGenerationFlow(input); 
    console.log('[FLOW_LOG] videoGenerationFlow completed.');
    return result;
  } catch (e) {
    const message = e instanceof Error ? e.message : 'Unknown flow error';
    console.error(`[FLOW_FATAL] Flow failed catastrophically: ${message}`, e);
    return { error: `Flow failed catastrophically: ${message}` };
  }
}

// Renamed and simplified to reflect it's now a single flow.
async function videoGenerationFlow(input: GenerateKissVideoInput): Promise<GenerateKissVideoOutput> {
    console.log('[FLOW_LOG] Starting video generation with a combined image.');
    
    const apiKey = process.env.POLLO_API_KEY;
    if (!apiKey) {
      console.error("[FLOW_ERROR] POLLO_API_KEY is not set.");
      throw new Error("POLLO_API_KEY is not set.");
    }
    console.log(`[FLOW_LOG] POLLO_API_KEY is present.`);
    
    const BASE_URL = "https://api.pollo.ai/v1";

    // Step 1: Submit video generation task to Pollo.ai using the combined image
    let taskId: string;
    try {
      const url = `${BASE_URL}/run/kling`;
      const headers = {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiKey}`,
      };
      const body = {
          input: {
            // The key is 'image', and we use the combined image from image1DataUri
            image: input.image1DataUri, 
            prompt: "Two people kissing, cinematic, high quality, 4k",
            length: 5,
            mode: "pro"
          }
      };

      console.log(`[DEBUG] Submitting video task to Pollo.ai at URL: ${url}`);
      console.log(`[DEBUG] Request Headers: ${JSON.stringify(headers, null, 2)}`);
      console.log(`[DEBUG] Request Body (first 100 chars of image): ${JSON.stringify({...body, input: {...body.input, image: body.input.image.substring(0, 100) + '...'}})}`);

      const createResponse = await fetch(url, {
        method: 'POST',
        headers: headers,
        body: JSON.stringify(body),
      });

      if (!createResponse.ok) {
        const errorBody = await createResponse.text();
        console.error(`[FLOW_ERROR] Failed to create video task. Status: ${createResponse.status}, Body: ${errorBody}`);
        throw new Error(`Failed to create video task. Status: ${createResponse.status}, Body: ${errorBody}`);
      }

      const createResult = await createResponse.json() as { task_id: string };
      taskId = createResult.task_id;
      console.log(`[FLOW_LOG] Video task created successfully. Task ID: ${taskId}`);

    } catch (error) {
      const message = error instanceof Error ? error.message : "Unknown error during task creation.";
      console.error(`[FLOW_ERROR] Pollo.ai task submission failed: ${message}`, error);
      return { error: `Pollo.ai task submission failed: ${message}` };
    }

    // Step 2. Poll for the video result
    try {
      let status: string | undefined;
      let pollCount = 0;
      const maxPolls = 60; // 60 polls * 5 seconds = 300 seconds timeout
      let videoUrl: string | undefined;

      while (status !== 'SUCCESS' && status !== 'FAILED' && pollCount < maxPolls) {
        pollCount++;
        await new Promise(resolve => setTimeout(resolve, 5000)); // Wait 5 seconds

        const statusUrl = `${BASE_URL}/task/${taskId}`;
        console.log(`[FLOW_LOG] Polling status from: ${statusUrl} (Attempt ${pollCount})`);
        const statusResponse = await fetch(statusUrl, {
          headers: { 'Authorization': `Bearer ${apiKey}` },
        });

        if (!statusResponse.ok) {
          console.warn(`[FLOW_WARN] Polling failed with status: ${statusResponse.status}`);
          continue; 
        }
        
        const result = await statusResponse.json() as { status: string, output?: { video: string }, error?: string };
        status = result.status;
        console.log(`[FLOW_LOG] Task status: ${status}`);

        if (status === 'SUCCESS') {
          if (result.output && result.output.video) {
            videoUrl = result.output.video;
            break;
          } else {
            console.error('[FLOW_ERROR] Task succeeded but no video URL was found in the response.', result);
            throw new Error("Task succeeded but no video URL was found in the response.");
          }
        } else if (status === 'FAILED') {
          console.error('[FLOW_ERROR] Video generation task failed with message:', result.error);
          throw new Error(result.error || "Video generation task failed.");
        }
      }

      if (!videoUrl) {
        throw new Error("Video generation timed out or did not return a URL.");
      }
      
      console.log(`[FLOW_LOG] Video generated successfully: ${videoUrl}`);

      // Step 3. Download the video and convert to data URI
      console.log(`[DEBUG] Downloading generated video from URL: ${videoUrl}`);
      const videoDownloadResponse = await fetch(videoUrl);
      if (!videoDownloadResponse.ok) {
        throw new Error(`Failed to download the generated video from Pollo.ai. Status: ${videoDownloadResponse.status}`);
      }
      
      const buffer = await videoDownloadResponse.arrayBuffer();
      const videoDataUri = `data:video/mp4;base64,${Buffer.from(buffer).toString('base64')}`;
      console.log('[FLOW_LOG] Video downloaded and converted to data URI.');
      
      return { videoDataUri };

    } catch (error) {
      const message = error instanceof Error ? error.message : "Unknown error during video polling/download.";
      console.error(`[FLOW_ERROR] Pollo.ai video generation failed: ${message}`, error);
      return { error: `Pollo.ai video generation failed: ${message}` };
    }
}
